+/// Get cached Uint8Array constructor (caches on first call)
+fn getUint8ArrayCtor(ctx: ?*qjs.JSContext) qjs.JSValue {
+    if (qjs.JS_IsUndefined(cached_uint8array_ctor)) {
+        const global = qjs.JS_GetGlobalObject(ctx);
